input.ui-inputfield, input.ui-autocomplete-input, textarea.ui-inputtextarea {

  &::-webkit-input-placeholder {
    color: @input-color-placeholder;
    .transition(none);
  }

  &::-moz-placeholder {
    color: @input-color-placeholder;
    .transition(none);
  }

  &:-ms-input-placeholder {
    color: @input-color-placeholder;
    .transition(none);
  }

  &.ui-state-error {
    &::-webkit-input-placeholder {
      color: @error-color;
    }

    &::-moz-placeholder {
      color: @error-color;
    }

    &:-ms-input-placeholder {
      color: @error-color;
    }
  }

}

body .ui-menu .ui-menu-list li.ui-widget-header {
    span.ui-icon-triangle-1-s {
        background-image: none;
        display: inline;
        position: relative;
        left: -8px;
        &:before {
            font-family: 'Glyphicons Halflings';
            color: @admin-text-color;
            position: relative;
            font-size: @glyphicon-icon-size;
            overflow: hidden;
            content: "\e259" !important;
        }
    }
    span.ui-icon-triangle-1-e {
        background-image: none;
        display: inline;
        position: relative;
        left: -8px;
        &:before {
            font-family: 'Glyphicons Halflings';
            color: @admin-text-color;
            position: relative;
            font-size: @glyphicon-icon-size;
            overflow: hidden;
            content: "\e258" !important;
        }
    }
}

> li {
  float: left;
  // Make the list-items overlay the bottom border
  margin-bottom: -1px;

  // Actual tabs (as links)
  > a {
    margin-right: 2px;
    line-height: @line-height-base;
    border: 1px solid transparent;
    border-radius: @border-radius-base @border-radius-base 0 0;
    outline: none;
    &:hover {
      border-color: @nav-tabs-link-hover-border-color @nav-tabs-link-hover-border-color @nav-tabs-border-color;
    }
  }

  // Active state, and its :hover to override normal :hover
  &.@{prefix-cls-nav}-active > a {
    &,
    &:hover,
    &:focus {
      color: @nav-tabs-active-link-hover-color;
      background-color: @nav-tabs-active-link-hover-bg;
      border: 1px solid @nav-tabs-active-link-hover-border-color;
      border-bottom-color: transparent;
      cursor: default;
    }
  }
}

> li {
  position: relative;
  display: block;

  > a {
    position: relative;
    display: block;
    padding: @nav-link-padding;
    color: @nav-link-default-color;
    &:hover,
    &:focus {
      color: @nav-link-hover-color;
      text-decoration: none;
      background-color: @nav-link-hover-bg;
    }
  }

  // Disabled state sets text to gray and nukes hover/tab effects
  &.@{prefix-cls-nav}-disabled > a {
    color: @nav-disabled-link-color;

    &:hover,
    &:focus {
      color: @nav-disabled-link-hover-color;
      text-decoration: none;
      background-color: transparent;
      cursor: @cursor-disabled;
    }
  }
}

& ul {
  & li {
    width: 25%;
    margin: 0 ~"calc(25% / 6)";
    height: 65px;
    position: relative;
    display: inline-block;
    background: fade(@primary-color, 55);
    border-radius: 6px;
    &:before {
      content: '';
      display: block;
      width: 24px;
      height: 24px;
      border-radius: 6px;
      background: #fff;
      position: absolute;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      margin: auto;
    }
    &:nth-child(2):before {
      transform: rotate(45deg);
    }
    &:nth-child(3):before {
      transform: rotate(45deg);
      filter: blur(2px);
    }
  }
}

& when not (@critical) {
    div.mage-error,
    div.field-error {
        margin-top: @form-field-error__margin-top;
        font-size: .9rem;
        color: var(--form-error-color, var(--danger-color));
    }
    .field-tooltip {
        --popover-width: @72;
        --popover-padding: @2 @3;
    }
    .field-tooltip-action {
        &::before {
            .breeze-icon(@icon-question-mark-circle, @5);
        }
    }
    .ui-datepicker {
        .ui-datepicker-calendar td {
            padding: 0;
        }
        &-trigger {
            &::before {
                .breeze-icon(@icon-calendar, @6);
            }
        }
        .ui-datepicker-title select {
            .padding(0 @4 0 @1);
            background-position: right @0-5 center;
            background-size: @4 @4;
        }
    }
}

& when not (@critical) {
    :where([id]) {
        scroll-margin-top: var(--base-scroll-margin-top);
    }
    .action.skip {
        .page-header & {
            position: absolute;
            .left(@2);
            top: @2;
            z-index: 40;
            text-align: center;
            background: var(--base-bg);
            color: var(--base-color);
            &:hover {
                text-decoration: underline;
            }
            &:focus-within {
                outline-offset: 0;
                padding: @container__padding;
            }
        }

        @media @media-md-down {
            // No need to have "skip" on mobile because layered nav is hidden
            .sidebar & {
                display: none !important;
            }
        }
    }
}

